func solve(nums []int64, queries [][]int64) int64 {
    mod := int64(1e9 + 7)
    for _, query := range queries {
        l, r, k, v := query[0], query[1], query[2], query[3]
        for idx := l; idx <= r; idx += k {
            nums[idx] = (nums[idx] * v) % mod
        }
    }
    var xor int64 = 0
    for _, num := range nums {
        xor ^= num
    }
    return xor
}
